/// Render adapter output for Claude Desktop / Claude Code / Co-Work (writes to claude.md).
pub fn render_claude_adapter(data: &str) -> String {
    let mut out = String::from("# AI Context OS — Claude Adapter Router\n");
    out.push_str(
        "# Auto-generated. Do not edit — this is a derived router artifact, not a canonical memory file.\n",
    );
    out.push_str(
        "# Do not store notes, scratch content, or permanent instructions here; edit canonical memories instead.\n\n",
    );
    out.push_str(data);
    out
}

