/// Render adapter output for tools following the AGENTS.md convention
/// (Codex, Aider, Jules, Continue, Cline and others). Writes to AGENTS.md.
pub fn render_agents_adapter(data: &str) -> String {
    let mut out = String::from("# AGENTS.md\n");
    out.push_str(
        "# Auto-generated by AI Context OS. Do not edit manually — this is a derived router artifact.\n",
    );
    out.push_str(
        "# Universal operating manual for agents in this workspace, not a place to store notes or repo-specific instructions.\n\n",
    );
    out.push_str(data);
    out
}
